(function(){function ready(fn){if(document.readyState!=="loading"){fn();return}document.addEventListener("DOMContentLoaded",fn)}ready(function(){var nav=document.getElementById("site-nav");if(nav){var button=nav.querySelector("button");var hidden=nav.querySelector(".hidden-links");if(button&&hidden){button.addEventListener("click",function(){hidden.classList.toggle("hidden");button.classList.toggle("close")})}}var urls=document.querySelector(".author__urls");function syncAuthorUrls(){if(!urls)return;urls.style.display=window.innerWidth>925?"block":"none"}syncAuthorUrls();window.addEventListener("resize",syncAuthorUrls,{passive:true})})})();
